// Normalise : minuscules + sans accents
function norm(s) {
  return String(s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
}

const allItems = $input.all();
if (!allItems.length) return [];

// Étape 1 — Trouver la ligne d'en-tête (celle où col_1 = "Projet")
let headerIdx = -1;
let colKeyMap = {};

for (let i = 0; i < allItems.length; i++) {
  const row = allItems[i].json;
  if (norm(String(row.col_1 || '')) === 'projet') {
    headerIdx = i;
    for (const [key, val] of Object.entries(row)) {
      if (key === 'row_number') continue;
      const v = String(val || '').trim();
      if (v && v !== 'empty') colKeyMap[norm(v)] = key;
    }
    break;
  }
}

if (headerIdx === -1) {
  return [{ json: {
    _debug: true,
    _message: 'Ligne d\'en-tête introuvable — col_1 doit contenir "Projet".',
    _premiere_ligne: allItems[0].json
  }}];
}

// Étape 2 — Mapping champs app → col_X
const ALIASES = {
  job_number:           ['projet'],
  client_name:          ['nom du client'],
  client_phone:         ['numero de telephone', 'telephone'],
  client_email:         ['courriel client', 'email'],
  job_address:          ['adresse'],
  work_type:            ['surface(s)', 'surfaces'],
  surface_type:         ['type de revetement'],
  total_sqft:           ['superficie approximative', 'superficie'],
  doors_count:          ['portes'],
  garage_doors_count:   ['porte garage', 'portes de garage'],
  windows_count:        ['fenetres'],
  floors_count:         ['nb d\'etages', 'etages'],
  duration_days:        ['duree prevue', 'duree'],
  colors_raw:           ['couleurs'],
  special_instructions: ['notes'],
  subtotal:             ['prix avant tx'],
  acompte_amount:       ['depot recu'],
  quote_date:           ['date du depot']
};

const resolved = {};
for (const [appField, aliases] of Object.entries(ALIASES)) {
  for (const alias of aliases) {
    if (colKeyMap[alias]) { resolved[appField] = colKeyMap[alias]; break; }
  }
}

if (!resolved.job_number) {
  return [{ json: {
    _debug: true,
    _message: 'Colonne "Projet" non trouvée dans les en-têtes détectés.',
    _entetes_detectes: colKeyMap
  }}];
}

// Étape 3 — Mapper les lignes de données (après la ligne d'en-tête)
const results = [];
for (let i = headerIdx + 1; i < allItems.length; i++) {
  const row = allItems[i].json;
  const jobNum = String(row[resolved.job_number] || '').trim();
  if (!jobNum || jobNum === 'empty') continue;

  const mapped = {};
  for (const [appField, colKey] of Object.entries(resolved)) {
    const val = String(row[colKey] || '').trim();
    if (val && val !== 'empty') mapped[appField] = val;
  }
  results.push({ json: mapped });
}

if (!results.length) {
  return [{ json: {
    _debug: true,
    _message: 'En-têtes trouvés mais aucune ligne avec un numéro de projet valide.',
    _resolved: resolved
  }}];
}

return results;
